insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('45547', 'la.ba', 'laba', '', '', '["Nomina","Nomina"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"selisih lebih antara harga penjualan yang lebih besar dan harga pembelian atau biaya produksi; keuntungan (yang diperoleh dengan menjual barang dengan harga lebih tinggi daripada pembeliannya, membungakan uang, dan sebagainya)","contoh":[{"nomor":2,"teks":"dari modal Rp50.000,00 diperolehnya -- Rp5.000,00 sehari"},{"nomor":4,"teks":"modal Rp100.000,00 --nya 2% sebulan"}]},{"nomor":"2","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"faedah; guna1; manfaat","contoh":[{"nomor":2,"teks":"apa --nya kita bertengkar seperti ini?"}]}]', '{"text":"[Sanskerta लाभ lābha n m ''keuntungan, pengetahuan, pendapatan, tambahan, hasil, capaian, temuan'']","languages":["Sanskerta"]}', '["berlaba","melabai","melabakan"]', '["laba bersih","laba bruto","laba ditahan","laba emiten","laba fiskal","laba komprehensif","laba kotor","laba kuartal","laba margin","laba mujur","laba normal","laba operasional","laba perang","laba perseroan","laba riil","laba rugi","laba usaha"]', '["adat juara kalah menang, adat saudagar laba rugi","akal laba-laba di gua, buruk suka merakut","berkelahi bagai laba-laba dalam gelas","jerih menentang boleh, rugi menentang laba","kalau laba bercikun-cikun, buruk diberi tahu orang","kurang taksir, hilang laba","laba sama dibagi, rugi sama diterjuni","laba tertinggal, harta lingkap","masuk tidak manjadi laba, keluar tidak membawa rugi","mengaut laba dengan siku","menggaut laba dengan siku","rugi menentang laba, jerih menentang boleh","seberat-berat beban, laba jangan ditinggalkan","tabuhan meminang anak laba-laba"]', '["masuk ke sarang laba-laba"]', '[{"peribahasa":"adat juara kalah menang, adat saudagar laba rugi","makna":"Dalam setiap persaingan atau usaha dagang, kemenangan dan kekalahan, keuntungan dan kerugian adalah hal yang lumrah dan tidak dapat dihindari."},{"peribahasa":"akal laba-laba di gua, buruk suka merakut","makna":"Menggambarkan seseorang yang memiliki kebiasaan buruk untuk mengambil keuntungan dari situasi yang tidak menguntungkan."},{"peribahasa":"berkelahi bagai laba-laba dalam gelas","makna":"Menggambarkan konflik atau perselisihan yang terjadi dalam ruang lingkup yang sempit dan tidak memberikan hasil yang berarti."},{"peribahasa":"jerih menentang boleh, rugi menentang laba","makna":"Menggambarkan usaha yang sia-sia atau tidak sebanding dengan hasil yang diharapkan."},{"peribahasa":"kalau laba bercikun-cikun, buruk diberi tahu orang","makna":"Menggambarkan seseorang yang hanya ingin menerima pujian atas keberhasilan tetapi tidak mau menerima kritik atas kesalahan."},{"peribahasa":"kurang taksir, hilang laba","makna":"Menggambarkan pentingnya perencanaan dan perhitungan yang matang untuk menghindari kerugian."},{"peribahasa":"laba sama dibagi, rugi sama diterjuni","makna":"Menggambarkan prinsip keadilan dalam berbagi keuntungan dan kerugian secara bersama-sama."},{"peribahasa":"laba tertinggal, harta lingkap","makna":"Menggambarkan situasi di mana keuntungan yang diharapkan tidak tercapai, bahkan harta yang ada pun hilang."},{"peribahasa":"masuk tidak manjadi laba, keluar tidak membawa rugi","makna":"Menggambarkan situasi yang netral, di mana tidak ada keuntungan atau kerugian yang diperoleh."},{"peribahasa":"mengaut laba dengan siku","makna":"Menggambarkan seseorang yang mengambil keuntungan dengan cara yang tidak jujur atau tidak adil."},{"peribahasa":"menggaut laba dengan siku","makna":"Menggambarkan tindakan yang sama dengan ''mengaut laba dengan siku'', yaitu mengambil keuntungan dengan cara yang tidak jujur."},{"peribahasa":"rugi menentang laba, jerih menentang boleh","makna":"Menggambarkan usaha yang sia-sia atau tidak sebanding dengan hasil yang diharapkan."},{"peribahasa":"seberat-berat beban, laba jangan ditinggalkan","makna":"Menggambarkan pentingnya tetap fokus pada tujuan utama meskipun menghadapi banyak rintangan."},{"peribahasa":"tabuhan meminang anak laba-laba","makna":"Menggambarkan usaha yang sia-sia atau tidak mungkin berhasil."}]');
