insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('45785', 'la.gi-la.gi', 'lagi-lagi', '', 'lagi', '["Adverbia"]', '[{"nomor":"1","kelasKata":[{"kode":"adv","nama":"Adverbia","tipe":"kelas_kata"}],"definisi":"berulang lagi; kembali lagi","contoh":[{"nomor":2,"teks":"~ mau pinjam uang"},{"nomor":4,"teks":"~ kau berkelahi dengan dia"}]}]', null, '[]', '[]', '[]', '[]', '[]');
insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('45782', 'la.gi', 'lagi', '', '', '["Adverbia","Adverbia","Adverbia","Partikel","Partikel"]', '[{"nomor":"1","kelasKata":[{"kode":"adv","nama":"Adverbia","tipe":"kelas_kata"}],"definisi":"sedang (dalam keadaan melakukan dan sebagainya); masih","contoh":[{"nomor":2,"teks":"jangan berisik, Ayah -- tidur"}]},{"nomor":"2","kelasKata":[{"kode":"adv","nama":"Adverbia","tipe":"kelas_kata"}],"definisi":"tambah sekian (atau sedemikian) pula","contoh":[{"nomor":2,"teks":"tunggu sebentar --"}]},{"nomor":"3","kelasKata":[{"kode":"adv","nama":"Adverbia","tipe":"kelas_kata"}],"definisi":"kembali (berbuat dan sebagainya) seperti semula; berulang seperti semula; pula","contoh":[{"nomor":2,"teks":"kemarin sudah menonton, sekarang hendak menonton --"}]},{"nomor":"4","kelasKata":[{"kode":"p","nama":"Partikel","tipe":"kelas_kata"}],"definisi":"dan; serta; juga","contoh":[{"nomor":2,"teks":"anak itu pandai -- rajin"},{"nomor":4,"teks":"istrinya muda, cantik, -- kaya"}]},{"nomor":"5","kelasKata":[{"kode":"p","nama":"Partikel","tipe":"kelas_kata"}],"definisi":"partikel yang dipakai untuk menekankan kata atau kalimat yang mendahuluinya (mengandung makna; sama sekali, betul-betul, amat sangat, dan sebagainya)","contoh":[{"nomor":2,"teks":"kekejaman tentara penjajah sungguh tak terkatakan --"},{"nomor":4,"teks":"penderitaan rakyat Kamboja sudah tidak tertahan --"}]}]', '{"text":"[Jawa Kuno lagi ''(arti dasar: penerusan dalam waktu; pada waktu sekarang, pada waktu lalu sampai waktu sekarang;dari sekarang sampai pada waktu yang akan datang) terus-menerus, tak henti-hentinya, berulang kali, selalu, senantiasa, biasanya; terus, telah beberapa waktu, berlanjut, tetap (berada atau berbuat), tetap tinggal; baru saja , pada waktu yang sama, sekali lagi; tak henti-hentinya pada waktu yang lalu, telah dalam waktu yang lama, dahulu kala, lebih dahulu, tradisional, yang biasa'']","languages":["Jawa Kuno"]}', '["lagi-lagi","lagian","selagi"]', '["lagi pula","lagi pun"]', '["belakang parang lagi jika diasah niscaya tajam","belum tentu lagi, ayam sedang disabung","berapalah tajam pisau parang, tajamlah lagi mulut manusia","bersuluh tengah hari (lagi terang lagi bersuluh)","bulang sali, kacak sama, tinggal lagi mujur malangnya","cekur jerangau, ada lagi di ubun-ubun","ikan lagi di laut, lada garam sudah dalam sengkalan","jalan mati lagi dicoba, ini pula jalan binasa","lagi ada jangan dimakan, sudah habis baru dimakan","lagi lauk, lagi nasi","lagi murah, lagi menawar (makin murah, makin menawar)","pisau senjata tiada bisa, bisa lagi mulut manusia","sendok dan periuk lagi berantuk (sendok dengan belanga lagi berlaga)","serta lalu kucing, tikus tiada berdecit lagi","seperti api makan lalang kering, tiada dapat dipadamkan lagi","sudah dapat gading bertuah, tanduk tiada berguna lagi","sudah terlalu hilir malam, apa hendak dikata lagi","tak terkayuhkan lagi biduk hilir","tersesak undang kepada yang runcing, tiada dapat bertenggang lagi","tidak hujan lagi becek, ini pula hujan"]', '[]', '[{"peribahasa":"belakang parang lagi jika diasah niscaya tajam","makna":"Meskipun seseorang memiliki keterbatasan intelektual, dengan ketekunan dan usaha yang sungguh-sungguh dalam belajar, ia akan dapat mencapai kepandaian."},{"peribahasa":"belum tentu lagi, ayam sedang disabung","makna":"Suatu hal yang belum ada keputusannya atau masih dalam proses, sehingga hasilnya belum dapat dipastikan."},{"peribahasa":"berapalah tajam pisau parang, tajamlah lagi mulut manusia","makna":"Perkataan atau ucapan seseorang dapat lebih menyakitkan dan melukai perasaan dibandingkan dengan senjata tajam."},{"peribahasa":"bersuluh tengah hari (lagi terang lagi bersuluh)","makna":"Melakukan tindakan yang sia-sia atau tidak perlu karena suatu hal sudah sangat jelas atau diketahui secara umum."},{"peribahasa":"bulang sali, kacak sama, tinggal lagi mujur malangnya","makna":"Dalam suatu persaingan atau pertandingan yang seimbang, hasil akhir (kemenangan atau kekalahan) sangat bergantung pada faktor keberuntungan atau nasib."},{"peribahasa":"cekur jerangau, ada lagi di ubun-ubun","makna":"Masih sangat muda dan belum memiliki pengalaman yang cukup."},{"peribahasa":"ikan lagi di laut, lada garam sudah dalam sengkalan","makna":"Bersiap-siap untuk menikmati atau mengecap hasil dari suatu pekerjaan atau hal yang belum pasti berhasil atau belum tentu didapatkan."},{"peribahasa":"jalan mati lagi dicoba, ini pula jalan binasa","makna":"Seseorang yang berani mengambil risiko atau melakukan tindakan berbahaya tanpa mempertimbangkan konsekuensinya."},{"peribahasa":"lagi ada jangan dimakan, sudah habis baru dimakan","makna":"Mengajarkan pentingnya hidup hemat dan menabung, yaitu tidak menghabiskan seluruh harta saat masih memiliki, melainkan menyisihkan untuk digunakan saat terdesak atau tidak lagi berpenghasilan."},{"peribahasa":"lagi lauk, lagi nasi","makna":"Semakin kaya seseorang, semakin banyak pula kenalan atau sahabat yang dimilikinya."},{"peribahasa":"lagi murah, lagi menawar (makin murah, makin menawar)","makna":"Menggambarkan sifat ketamakan, di mana seseorang yang telah diberikan sesuatu atau memperoleh kesenangan akan berkeinginan untuk mendapatkan lebih banyak lagi."},{"peribahasa":"pisau senjata tiada bisa, bisa lagi mulut manusia","makna":"Perkataan atau ucapan seseorang dapat lebih menyakitkan dan melukai perasaan dibandingkan dengan senjata tajam, karena luka batin lebih sulit disembuhkan daripada luka fisik."},{"peribahasa":"sendok dan periuk lagi berantuk (sendok dengan belanga lagi berlaga)","makna":"Menggambarkan bahwa perselisihan atau pertengkaran dapat terjadi bahkan di antara orang-orang yang memiliki hubungan sangat dekat, seperti suami istri atau saudara."},{"peribahasa":"serta lalu kucing, tikus tiada berdecit lagi","makna":"Menggambarkan situasi di mana kehadiran seseorang yang dihormati atau ditakuti dapat menghentikan keributan atau perilaku tidak tertib."},{"peribahasa":"seperti api makan lalang kering, tiada dapat dipadamkan lagi","makna":"Menggambarkan suatu masalah atau bahaya yang telah membesar dan menjadi sangat sulit atau tidak mungkin lagi untuk dikendalikan atau dihentikan."},{"peribahasa":"sudah dapat gading bertuah, tanduk tiada berguna lagi","makna":"Apabila seseorang telah memperoleh sesuatu yang lebih baik atau berharga, maka hal yang lama (yang kurang baik atau tidak lagi diperlukan) akan ditinggalkan atau dianggap tidak berguna."},{"peribahasa":"sudah terlalu hilir malam, apa hendak dikata lagi","makna":"Suatu kesalahan atau perbuatan buruk yang telah terjadi dan tidak dapat diubah atau diperbaiki lagi."},{"peribahasa":"tak terkayuhkan lagi biduk hilir","makna":"Menggambarkan kondisi seseorang yang sudah sangat lemah atau tidak berdaya untuk melanjutkan suatu usaha atau perjuangan."},{"peribahasa":"tersesak undang kepada yang runcing, tiada dapat bertenggang lagi","makna":"Menggambarkan kondisi seseorang yang sudah tidak berdaya atau kehabisan akal untuk mencari solusi, sehingga tidak dapat lagi menunda atau menghindari suatu masalah."},{"peribahasa":"tidak hujan lagi becek, ini pula hujan","makna":"Menggambarkan situasi di mana seseorang sudah berada dalam kesulitan atau masalah, dan kemudian ditimpa lagi dengan masalah lain yang memperburuk keadaan."}]');
insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('146553', 'la.gi', 'lagi', '', '', '["Nomina","Batak"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"},{"kode":"Bt","nama":"Batak","tipe":"bahasa"}],"definisi":"ujung biji padi","contoh":[]}]', '{"text":"[Jawa Kuno lagi ''(arti dasar: penerusan dalam waktu; pada waktu sekarang, pada waktu lalu sampai waktu sekarang;dari sekarang sampai pada waktu yang akan datang) terus-menerus, tak henti-hentinya, berulang kali, selalu, senantiasa, biasanya; terus, telah beberapa waktu, berlanjut, tetap (berada atau berbuat), tetap tinggal; baru saja , pada waktu yang sama, sekali lagi; tak henti-hentinya pada waktu yang lalu, telah dalam waktu yang lama, dahulu kala, lebih dahulu, tradisional, yang biasa'']","languages":["Jawa Kuno"]}', '[]', '[]', '[]', '[]', '[]');
insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('45788', 'la.gi.ah', 'lagiah', '', '', '["Nomina","Arab"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"},{"kode":"Ar","nama":"Arab","tipe":"lainnya"}],"definisi":"perkataan yang tidak berguna, tidak berisi, dan belum tentu benar","contoh":[]}]', '{"text":"[Arab لَاغِيَةٌ lāgiyah n sg f ''perkataan yang tidak berguna; perkataan tercela'']","languages":["Arab"]}', '[]', '[]', '[]', '[]', '[]');
