insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('45885', 'la.in', 'lain', '', '', '["Adjektiva","Adjektiva","Adjektiva"]', '[{"nomor":"1","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"}],"definisi":"Bersifat berbeda atau tidak sama, baik dalam hal bentuk, sifat, rupa, maupun karakteristiknya, sehingga dapat dibedakan dari yang lain.","contoh":[{"nomor":1,"teks":"Pendapatnya berbeda dari yang lain karena didasarkan pada penelitian lapangan."},{"nomor":2,"teks":"Gaya berpakaian mahasiswa ini tampak lain dibandingkan teman-teman seangkatannya."},{"nomor":3,"teks":"Setiap karya seni memiliki keunikan yang membedakannya dari karya seni lain."}]},{"nomor":"2","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"}],"definisi":"Kecuali atau tidak termasuk dalam kategori, kelompok, atau hitungan yang dimaksud.","contoh":[{"nomor":1,"teks":"Harga yang tercantum adalah Rp5.000,00, lain ongkos kirim."},{"nomor":2,"teks":"Semua siswa hadir dalam acara tersebut, lain Andi yang sedang sakit."},{"nomor":3,"teks":"Diskon ini berlaku untuk semua produk, lain barang elektronik."}]},{"nomor":"3","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"}],"definisi":"Berbeda pendapat atau tidak sejalan dalam pandangan, sikap, atau perasaan terhadap suatu hal.","contoh":[{"nomor":1,"teks":"Kedua pihak memiliki pandangan yang lain terkait solusi masalah tersebut."},{"nomor":2,"teks":"Masyarakat desa itu memiliki tradisi yang lain dibandingkan desa tetangga."},{"nomor":3,"teks":"Selera kuliner setiap orang tentu lain sesuai latar belakang dan kebiasaan."}]}]', null, '["berkelainan","berlain-lainan","berlainan","kelainan","melaini","melainkan","memperlain","memperlainkan","perlainan"]', '["lain dari itu","lain halnya","lain kali"]', '["asing orang, lain pendapat","asing udang, lain nikmat","awak yang payah membelah ruyung, orang lain yang beroleh sagunya","diserakkan padi awak diimbaukan orang lain","kepala sama hitam (berbulu), pendapat berlain-lain","lain bengkak, lain bernanah","lain bengkak, lain menanah","lain biduk, lain di galang","lain di mulut, lain di hati","lain dulang lain kaki, lain orang lain hati","lain gatal, lain digaruk","lain kumpang, lain parang","lain ladang lain belalang, lain lubuk lain ikannya","lain orang memperanakkan, lain orang dipanggil bapa","lain padang, lain belalang","lain sakit lain diobat, lain luka lain dibebat","lain yang diagak, lain yang kena"]', '["berat pada mata orang lain","hidup di bawah bendera negara lain","lain dulu, lain sekarang","menari di atas genderang orang lain","tidak lain tidak bukan"]', '[{"peribahasa":"asing orang, lain pendapat","makna":"Setiap individu memiliki pandangan, pemikiran, atau preferensi yang berbeda-beda."},{"peribahasa":"asing udang, lain nikmat","makna":"Setiap orang memiliki selera, kebiasaan, atau kesenangan yang berbeda-beda sesuai lingkungannya."},{"peribahasa":"awak yang payah membelah ruyung, orang lain yang beroleh sagunya","makna":"Seseorang yang bekerja keras, tetapi hasilnya dinikmati oleh orang lain."},{"peribahasa":"diserakkan padi awak diimbaukan orang lain","makna":"Mengutamakan orang lain hingga mengabaikan kepentingan sendiri atau keluarga."},{"peribahasa":"kepala sama hitam (berbulu), pendapat berlain-lain","makna":"Meskipun manusia sama-sama memiliki sifat dasar yang mirip, pandangan dan pendapat mereka dapat berbeda."},{"peribahasa":"lain bengkak, lain bernanah","makna":"Orang yang bersalah bukanlah orang yang menanggung akibatnya, melainkan pihak lain."},{"peribahasa":"lain bengkak, lain menanah","makna":"Orang yang bersalah bukanlah orang yang menanggung akibatnya, melainkan pihak lain."},{"peribahasa":"lain biduk, lain di galang","makna":"Jawaban atau tindakan yang tidak sesuai dengan pertanyaan atau maksud sebenarnya."},{"peribahasa":"lain di mulut, lain di hati","makna":"Perkataan tidak sesuai dengan isi hati, menunjukkan ketidakjujuran."},{"peribahasa":"lain dulang lain kaki, lain orang lain hati","makna":"Setiap orang memiliki perbedaan dalam pandangan dan perasaan."},{"peribahasa":"lain gatal, lain digaruk","makna":"Memberikan jawaban atau melakukan tindakan yang tidak sesuai dengan masalah yang dihadapi."},{"peribahasa":"lain kumpang, lain parang","makna":"Keadaan atau cara yang berbeda dari sebelumnya."},{"peribahasa":"lain ladang lain belalang, lain lubuk lain ikannya","makna":"Setiap tempat atau daerah memiliki adat istiadat, kebiasaan, atau aturan yang berbeda."},{"peribahasa":"lain orang memperanakkan, lain orang dipanggil bapa","makna":"Seseorang yang bekerja keras atau berjasa, tetapi orang lain yang mendapatkan penghargaan."},{"peribahasa":"lain padang, lain belalang","makna":"Setiap daerah atau lingkungan memiliki kondisi dan kebiasaan yang berbeda."},{"peribahasa":"lain sakit lain diobat, lain luka lain dibebat","makna":"Solusi yang diberikan tidak sesuai dengan masalah yang dihadapi."},{"peribahasa":"lain yang diagak, lain yang kena","makna":"Hasil yang didapat berbeda dari yang direncanakan atau diharapkan."}]');
