insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('46012', 'lak.sa.na', 'laksana', '', '', '["Nomina","Klasik","Partikel","Nomina","Arkeologi"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"},{"kode":"kl","nama":"Klasik","tipe":"kelas_kata"}],"definisi":"tanda yang baik; sifat; laku; perbuatan","contoh":[]},{"nomor":"2","kelasKata":[{"kode":"p","nama":"Partikel","tipe":"kelas_kata"}],"definisi":"seperti; sebagai","contoh":[{"nomor":2,"teks":"-- pinang dibelah dua"}]},{"nomor":"3","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"},{"kode":"Ark","nama":"Arkeologi","tipe":"lainnya"}],"definisi":"benda yang dipegang dan menjadi tanda khusus suatu arca","contoh":[]}]', '{"text":"[Sanskerta लक्षण lakṣaṇa ''definisi, petunjuk, indikasi'' atau लक्षणा lakṣaṇā ''indikasi, kualitas, tanda'']","languages":["Sanskerta"]}', '["keterlaksanaan","melaksanakan","pelaksana","pelaksanaan","terlaksana","terlaksanakan"]', '["laksana istri","laksana perempuan"]', '["hidung laksana kuntum seroja, dada seperti mawar merekah","laksana antah lemukut, lapar sangat baru berguna","laksana apung dipermainkan gelombang","laksana batik Lasem","laksana bunga dadap, sungguh merah berbau tidak","laksana bunga dedap, sungguh merah, berbau tidak","laksana golok kayu, ditetakkan tak makan, dijual tak laku","laksana janda baru bangun","laksana jentayu menantikan hujan","laksana kerbau, di mana rumput hijau, di sana menerkam","laksana manau, seribu kali embat haram tak patah","laksana mengaprit di tengah laut, dipukul ombak jatuh ke tepi","laksana mestika gamat"]', '["laksana taji dibentuk"]', '[{"peribahasa":"hidung laksana kuntum seroja, dada seperti mawar merekah","makna":"Menggambarkan keindahan fisik seorang wanita, khususnya hidung yang indah dan dada yang merekah seperti mawar."},{"peribahasa":"laksana antah lemukut, lapar sangat baru berguna","makna":"Sesuatu yang dianggap tidak berharga atau kurang baik, namun akan menjadi berguna ketika seseorang berada dalam kondisi yang sangat membutuhkan."},{"peribahasa":"laksana apung dipermainkan gelombang","makna":"Menggambarkan kondisi hidup yang tidak menentu, seringkali dalam kemiskinan, terutama saat berada di perantauan atau negeri asing."},{"peribahasa":"laksana batik Lasem","makna":"Sesuatu yang semakin lama digunakan atau semakin tua usianya, akan semakin baik atau berharga."},{"peribahasa":"laksana bunga dadap, sungguh merah berbau tidak","makna":"Seseorang yang memiliki paras rupawan, namun tidak diimbangi dengan budi pekerti atau akhlak yang baik."},{"peribahasa":"laksana bunga dedap, sungguh merah, berbau tidak","makna":"Seseorang yang memiliki paras rupawan, namun tidak diimbangi dengan budi pekerti atau akhlak yang baik."},{"peribahasa":"laksana golok kayu, ditetakkan tak makan, dijual tak laku","makna":"Sesuatu yang tidak memiliki nilai guna atau tidak efektif, sehingga tidak dapat dimanfaatkan maupun diperjualbelikan."},{"peribahasa":"laksana janda baru bangun","makna":"Menggambarkan seorang perempuan yang sangat cantik atau menarik."},{"peribahasa":"laksana jentayu menantikan hujan","makna":"Menggambarkan kerinduan yang sangat mendalam terhadap sesuatu atau seseorang."},{"peribahasa":"laksana kerbau, di mana rumput hijau, di sana menerkam","makna":"Seseorang yang mengabaikan potensi bahaya karena terlalu tergiur oleh sesuatu yang menarik atau menguntungkan."},{"peribahasa":"laksana manau, seribu kali embat haram tak patah","makna":"Menggambarkan sesuatu yang sangat kuat, tangguh, dan tidak mudah rusak atau patah meskipun menghadapi berbagai cobaan."},{"peribahasa":"laksana mengaprit di tengah laut, dipukul ombak jatuh ke tepi","makna":"Menggambarkan kondisi hidup yang tidak stabil, melarat, dan terombang-ambing, terutama saat berada di perantauan atau dalam situasi yang tidak menentu."},{"peribahasa":"laksana mestika gamat","makna":"Menggambarkan rupa, perilaku, atau perkataan yang sangat baik dan indah."}]');
