insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('46119', 'la.lu', 'lalu', '', '', '["Verba","Verba","Verba","Verba","Verba","Partikel","Verba","Verba"]', '[{"nomor":"1","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"berjalan lewat","contoh":[{"nomor":2,"teks":"dilarang -- di jalan ini"}]},{"nomor":"2","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"berkata (langsung) semaunya","contoh":[{"nomor":2,"teks":"ia berbicara asal -- saja"}]},{"nomor":"3","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"sudah lewat; sudah lampau","contoh":[{"nomor":2,"teks":"tahun yang --"}]},{"nomor":"4","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"habis1; selesai","contoh":[{"nomor":2,"teks":"pertandingan telah --"},{"nomor":4,"teks":"peperangan telah --"}]},{"nomor":"5","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"lintas (dapat masuk terus); lulus","contoh":[]},{"nomor":"6","kelasKata":[{"kode":"p","nama":"Partikel","tipe":"kelas_kata"}],"definisi":"kemudian; lantas","contoh":[]},{"nomor":"7","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"tidak boleh ditebus kembali (tentang barang gadaian)","contoh":[{"nomor":2,"teks":"empat hari lagi gadaianku --"}]},{"nomor":"8","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"berlangsung; berlanjut","contoh":[]}]', null, '["berkelaluan","berlalu","kelaluan","keterlaluan","laluan","melalui","melalukan","terlalu"]', '["lalu akal"]', '["air lalu berkubak tohor","angan lalu, paham bertumbuk","angan lalu, paham tertumbuk","bagai denai gajah lalu","bala lalu dibawa singgah","bertitah lalu sembah berlaku","biduk lalu, kiambang bertaut","gajah lalu dibeli, kusa tidak terbeli","gajah lalu dibeli, rusa tidak terbeli","jalan dialih orang lalu, cupak dipapak orang penggalas","jika tak lalu dandang di air, di gurun dirangkakkan (ditanjakkan)","kalau di bawah melompat, lalu di atas menyusup","kalau pandai mencencang akar, mati lalu ke pucuknya","laki pulang kelaparan, dagang lalu ditanakkan","lalu (lulus) ujung, lalu (lulus) kelindan","lalu penjahit, lalu kelindan","mabuk di enggang lalu","mara hinggap mara terbang, enggang lalu ranting patah","menunggu angin lalu","sambil menyeruduk (menyuruk) galas lalu","serta lalu kucing, tikus tiada berdecit lagi","sesak berundur-undur, hendak lari malu, hendak menghambat tak lalu","setapak jangan lalu, setapak jangan surut","setempuh lalu, sebondong surut","seperti ditempuh gajah lalu","takut titik, lalu tumpah","upah lalu, bandar tak masuk","yang terbujur lalu, yang terlintang patah"]', '[]', '[{"peribahasa":"air lalu berkubak tohor","makna":"Penghasilan yang diterima cepat habis untuk membayar utang atau memenuhi kebutuhan, sehingga tidak tersisa."},{"peribahasa":"angan lalu, paham bertumbuk","makna":"Keinginan atau rencana yang sulit diwujudkan karena banyaknya halangan atau rintangan."},{"peribahasa":"angan lalu, paham tertumbuk","makna":"Keinginan atau rencana yang sulit diwujudkan karena banyaknya halangan atau rintangan."},{"peribahasa":"bagai denai gajah lalu","makna":"Sesuatu yang besar atau signifikan tidak dapat disembunyikan, karena akan meninggalkan jejak yang jelas."},{"peribahasa":"bala lalu dibawa singgah","makna":"Sengaja mencari atau mengundang kesusahan dan masalah."},{"peribahasa":"bertitah lalu sembah berlaku","makna":"Apabila seseorang memenuhi kehendak atau permintaan orang lain, maka kehendak atau permintaannya sendiri juga akan dipenuhi."},{"peribahasa":"biduk lalu, kiambang bertaut","makna":"Perselisihan atau pertengkaran antara dua pihak, terutama sanak saudara, tidak perlu dicampuri karena pada akhirnya mereka akan berbaikan kembali."},{"peribahasa":"gajah lalu dibeli, kusa tidak terbeli","makna":"Melakukan sesuatu yang besar atau penting, namun mengabaikan hal-hal kecil yang sebenarnya krusial untuk menunjang keberhasilan tersebut."},{"peribahasa":"gajah lalu dibeli, rusa tidak terbeli","makna":"Melakukan sesuatu yang besar atau penting, namun mengabaikan hal-hal kecil yang sebenarnya krusial untuk menunjang keberhasilan tersebut."},{"peribahasa":"jalan dialih orang lalu, cupak dipapak orang penggalas","makna":"Adat istiadat atau kebiasaan suatu daerah yang diubah atau dipengaruhi oleh orang asing atau pendatang."},{"peribahasa":"jika tak lalu dandang di air, di gurun dirangkakkan (ditanjakkan)","makna":"Menggunakan segala daya upaya dan metode, bahkan yang tidak konvensional atau sulit, untuk mencapai suatu tujuan."},{"peribahasa":"kalau di bawah melompat, lalu di atas menyusup","makna":"Kemampuan untuk beradaptasi dan menyesuaikan diri dengan berbagai keadaan atau lingkungan sosial."},{"peribahasa":"kalau pandai mencencang akar, mati lalu ke pucuknya","makna":"Seseorang yang memiliki keahlian atau strategi yang tepat dapat mengatasi masalah besar dengan mudah, atau mengalahkan lawan dengan sekali tindakan."},{"peribahasa":"laki pulang kelaparan, dagang lalu ditanakkan","makna":"Mengesampingkan urusan atau kebutuhan pribadi demi mengutamakan urusan atau kepentingan orang lain."},{"peribahasa":"lalu (lulus) ujung, lalu (lulus) kelindan","makna":"Apabila tujuan utama atau bagian tersulit dari suatu usaha telah tercapai, maka bagian-bagian lain yang menyertainya akan lebih mudah diselesaikan."},{"peribahasa":"lalu penjahit, lalu kelindan","makna":"Apabila tujuan utama atau bagian tersulit dari suatu usaha telah tercapai, maka bagian-bagian lain yang menyertainya akan lebih mudah diselesaikan."},{"peribahasa":"mabuk di enggang lalu","makna":"Merasa sangat tertarik atau terpikat pada seseorang yang baru dikenal."},{"peribahasa":"mara hinggap mara terbang, enggang lalu ranting patah","makna":"Seseorang yang tidak bersalah namun terlibat dalam suatu masalah atau kesalahan, atau suatu kejadian kebetulan yang menimbulkan konsekuensi."},{"peribahasa":"menunggu angin lalu","makna":"Menunggu dengan sia-sia atau melakukan pekerjaan yang tidak menghasilkan apa-apa."},{"peribahasa":"sambil menyeruduk (menyuruk) galas lalu","makna":"Mencapai tujuan atau mendapatkan keuntungan sambil bersenang-senang atau tanpa bersusah payah."},{"peribahasa":"serta lalu kucing, tikus tiada berdecit lagi","makna":"Menggambarkan situasi di mana kehadiran seseorang yang dihormati atau ditakuti dapat menghentikan keributan atau perilaku tidak tertib."},{"peribahasa":"sesak berundur-undur, hendak lari malu, hendak menghambat tak lalu","makna":"Seseorang yang berada dalam situasi sulit, tidak mampu bergerak maju atau mundur, dan merasa malu untuk mengakui kekalahan atau ketidakmampuan."},{"peribahasa":"setapak jangan lalu, setapak jangan surut","makna":"Memiliki pendirian yang teguh dan tidak mudah goyah dalam menghadapi berbagai situasi."},{"peribahasa":"setempuh lalu, sebondong surut","makna":"Menjaga persatuan dan kesepakatan dalam suatu kelompok atau persahabatan."},{"peribahasa":"seperti ditempuh gajah lalu","makna":"Suatu hal yang buruk atau signifikan yang tidak dapat ditutup-tutupi atau disembunyikan lagi."},{"peribahasa":"takut titik, lalu tumpah","makna":"Karena terlalu takut akan kerugian kecil, seseorang justru mengalami kerugian yang jauh lebih besar."},{"peribahasa":"upah lalu, bandar tak masuk","makna":"Suatu usaha yang tidak mendatangkan hasil atau keuntungan sama sekali, bahkan dapat menyebabkan kerugian."},{"peribahasa":"yang terbujur lalu, yang terlintang patah","makna":"Sesuatu yang tidak dapat dihalang-halangi atau suatu perintah yang harus dipatuhi tanpa pengecualian."}]');
