insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('46571', 'la.ngit', 'langit', '', '', '["Nomina"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"ruang luas yang terbentang di atas bumi, tempat terlihatnya bulan, bintang, matahari, dan planet yang lain","contoh":[]}]', null, '["kelangitan","langit-langit","lelangit","melangit","melangitkan","selangit"]', '["langit air","langit berawan","langit berawan sedikit","langit bersih","langit tenggiri","langit tertutup","lelangit mutlak"]', '["ampang sampai ke seberang, dinding sampai ke langit","angan-angan menerawang langit","bintang di langit boleh dibilang, tetapi arang di muka tak sadar","di mana bumi dipijak, di sana langit dijunjung","di mana bumi dipijak, di situ langit dijunjung","di mana tanah dipijak, di situ langit dijunjung","disigai sampai ke langit (tinggi disigai, besar ditebang)","duduk di dalam tabir, langit-langit berbau tembelang","empang sampai ke seberang, dinding sampai ke langit","gereklah langit olehmu, engkau takkan kusaraki juga","harapkan guruh (guntur) di langit, air di tempayan ditumpahkan","hujan berbalik ke langit","jadi bumi langit","kalau langit hendak menimpa bumi, bolehkah ditahan dengan telunjuk","ke langit tak sampai, ke bumi tak nyata","kelekatu hendak terbang ke langit","meludah ke langit, muka juga yang basah","menengadah ke langit hijau","menggantang asap, mengukir langit","mengharapkan hujan di langit, air di tempayan ditumpahkan","mengukir langit"]', '["bak bumi dan langit","beratapkan langit","di kolong langit","jalur langit","jatuh dari langit","sawah berbandar langit","sebagai bumi dan langit","setinggi langit","seperti bumi dengan langit"]', '[{"peribahasa":"ampang sampai ke seberang, dinding sampai ke langit","makna":"Melakukan suatu pekerjaan dengan sungguh-sungguh dan totalitas untuk mencapai tujuan yang maksimal."},{"peribahasa":"angan-angan menerawang langit","makna":"Memiliki cita-cita atau harapan yang sangat tinggi dan idealis, terkadang sulit untuk dicapai."},{"peribahasa":"bintang di langit boleh dibilang, tetapi arang di muka tak sadar","makna":"Seseorang yang mudah melihat dan membicarakan kekurangan atau kesalahan orang lain, namun tidak menyadari atau tidak mau mengakui kekurangan atau kesalahan pada dirinya sendiri."},{"peribahasa":"di mana bumi dipijak, di sana langit dijunjung","makna":"Seseorang harus mampu beradaptasi dan menghormati adat istiadat serta norma yang berlaku di tempat ia tinggal atau kunjungi."},{"peribahasa":"di mana bumi dipijak, di situ langit dijunjung","makna":"Seseorang harus mampu beradaptasi dan menghormati adat istiadat serta norma yang berlaku di tempat ia tinggal atau kunjungi."},{"peribahasa":"di mana tanah dipijak, di situ langit dijunjung","makna":"Seseorang harus mampu beradaptasi dan menghormati adat istiadat serta norma yang berlaku di tempat ia tinggal atau kunjungi."},{"peribahasa":"disigai sampai ke langit (tinggi disigai, besar ditebang)","makna":"Menyelidiki atau mengusut suatu perkara secara tuntas dan mendalam untuk menemukan kebenaran."},{"peribahasa":"duduk di dalam tabir, langit-langit berbau tembelang","makna":"Seseorang yang jarang berinteraksi di luar, namun reputasi buruk atau tabiatnya telah tersebar luas."},{"peribahasa":"empang sampai ke seberang, dinding sampai ke langit","makna":"Melakukan suatu pekerjaan dengan sungguh-sungguh dan totalitas untuk mencapai tujuan yang maksimal."},{"peribahasa":"gereklah langit olehmu, engkau takkan kusaraki juga","makna":"Berusaha keras untuk menarik perhatian, namun tidak ada yang peduli atau menghiraukan."},{"peribahasa":"harapkan guruh (guntur) di langit, air di tempayan ditumpahkan","makna":"Mengharapkan keuntungan besar yang belum pasti, sehingga melepaskan keuntungan kecil yang sudah ada, yang pada akhirnya tidak mendapatkan apa-apa."},{"peribahasa":"hujan berbalik ke langit","makna":"Situasi yang tidak lazim atau terbalik dari seharusnya, di mana pihak yang lebih kuat atau berilmu meminta bantuan atau nasihat kepada pihak yang lebih lemah atau kurang berpengalaman."},{"peribahasa":"jadi bumi langit","makna":"Menjadi seseorang yang sangat diandalkan dan dihormati, tempat orang lain menggantungkan nasib dan harapan."},{"peribahasa":"kalau langit hendak menimpa bumi, bolehkah ditahan dengan telunjuk","makna":"Sesuatu yang besar dan tidak terhindarkan tidak dapat dicegah atau dihentikan oleh upaya yang kecil atau tidak berdaya."},{"peribahasa":"ke langit tak sampai, ke bumi tak nyata","makna":"Melakukan sesuatu secara setengah-setengah atau tidak tuntas, sehingga tidak mencapai tujuan yang tinggi maupun menghasilkan sesuatu yang nyata."},{"peribahasa":"kelekatu hendak terbang ke langit","makna":"Menghendaki atau berusaha mencapai sesuatu yang mustahil atau tidak mungkin berhasil."},{"peribahasa":"meludah ke langit, muka juga yang basah","makna":"Perbuatan mencela atau merendahkan orang lain, terutama yang lebih tinggi kedudukannya, pada akhirnya akan merugikan diri sendiri."},{"peribahasa":"menengadah ke langit hijau","makna":"Tidak ada harapan untuk mendapatkan pertolongan atau berada dalam keadaan putus asa."},{"peribahasa":"menggantang asap, mengukir langit","makna":"Melakukan perbuatan yang sia-sia, tidak mungkin berhasil, atau hanya berangan-angan tanpa hasil nyata."},{"peribahasa":"mengharapkan hujan di langit, air di tempayan ditumpahkan","makna":"Mengharapkan keuntungan besar yang belum pasti, sehingga melepaskan keuntungan kecil yang sudah ada, yang pada akhirnya tidak mendapatkan apa-apa."},{"peribahasa":"mengukir langit","makna":"Melakukan perbuatan yang sia-sia atau tidak mungkin berhasil."}]');
