m","lari maraton","lari nikah","lari rintangan","lari santai"]', '["dari lecah lari ke duri","hujan turun, kambing lari","membekali budak lari","putih tapaknya lari","sesak berundur-undur, hendak lari malu, hendak menghambat tak lalu","tak akan (takkan) lari gunung dikejar, hilang kabut tampaklah dia","tak kan lari gunung dikejar, hilang kabut tampaklah dia","takut akan lumpur, lari ke duri"]', '[]', '[{"peribahasa":"dari lecah lari ke duri","makna":"Berusaha menghindari masalah kecil, namun justru mendapatkan masalah yang lebih besar atau lebih sulit."},{"peribahasa":"hujan turun, kambing lari","makna":"Ungkapan yang digunakan untuk menandakan berakhirnya suatu cerita atau perkara."},{"peribahasa":"membekali budak lari","makna":"Melakukan perbuatan yang sia-sia, yaitu mencoba melawan pihak yang lebih kuat atau berkuasa tanpa memiliki kemampuan yang memadai."},{"peribahasa":"putih tapaknya lari","makna":"Berlari dengan sangat cepat karena ketakutan yang luar biasa."},{"peribahasa":"sesak berundur-undur, hendak lari malu, hendak menghambat tak lalu","makna":"Seseorang yang berada dalam situasi sulit, tidak mampu bergerak maju atau mundur, dan merasa malu untuk mengakui kekalahan atau ketidakmampuan."},{"peribahasa":"tak akan (takkan) lari gunung dikejar, hilang kabut tampaklah dia","makna":"Tidak perlu tergesa-gesa dalam melakukan sesuatu yang sudah pasti, karena pada waktunya akan terlihat hasilnya."},{"peribahasa":"tak kan lari gunung dikejar, hilang kabut tampaklah dia","makna":"Tidak perlu tergesa-gesa dalam melakukan sesuatu yang sudah pasti, karena pada waktunya akan terlihat hasilnya."},{"peribahasa":"takut akan lumpur, lari ke duri","makna":"Menghindari masalah kecil, namun justru terjebak dalam masalah yang lebih besar atau lebih sulit."}]');
