insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('47340', 'la.ut', 'laut', '', '', '["Nomina"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"kumpulan air asin (dalam jumlah yang banyak dan luas) yang menggenangi dan membagi daratan atas benua atau pulau; bahar1","contoh":[]}]', null, '["kelautan","lautan","melaut","melauti","melautkan","pelaut","pelautan"]', '["Laut Baltik","laut bebas","Laut Cina Selatan","laut dalam","Laut Hitam","laut ingresi","Laut Karibia","laut kidul","Laut Kuning","laut lepas","laut madu","Laut Mati","Laut Merah","laut pedalaman","laut pertengahan","laut rembang","laut selebu","laut tengah","laut tepi","laut tepian","laut teritorial","Laut Utara"]', '["air laut asin sendiri","air laut pun ada pasang surutnya","asam di darat, ikan di laut (garam di laut asam di gunung) bertemu dalam belanga","bagai menunggangkan air ke laut","dalam laut boleh diajuk, dalam hati siapa tahu","diam di laut masin tidak, diam di bandar tak meniru","garam di laut, asam di gunung bertemu dalam belanga juga","ikan di laut, asam di gunung, bertemu dalam belanga","ikan lagi di laut, lada garam sudah dalam sengkalan","itik berenang di laut (air), mati kehausan","jika benih yang baik jatuh ke laut, menjadi pulau","kalau kail panjang sejengkal, jangan laut hendak diduga","karam di darat ada juga tinggal tungku lekar, karam di laut habis sekali","karam di laut dapat direnangi, karam di hati bilakan sudah","laksana mengaprit di tengah laut, dipukul ombak jatuh ke tepi","laut budi tepian akal","laut ditembak, darat kena","laut ditimba akan kering","laut madu berpantaikan sakar (gula)","laut mana yang tak berombak, bumi mana yang tak ditimpa hujan","laut tidak membuang sungai, rimba tidak membuang latah","membuang garam ke laut","menambak gunung, menggarami air laut","menambak gunung, menggarami laut","menambak ke laut","menunggu laut kering","sekepal menjadi gunung, setitik menjadi laut","sungguhpun kawat yang dibentuk, ikan di laut yang diadang","tak ada laut yang tak berombak"]', '[]', '[{"peribahasa":"air laut asin sendiri","makna":"Sindiran bagi orang yang suka memuji diri sendiri."},{"peribahasa":"air laut pun ada pasang surutnya","makna":"Nasib manusia tidak selalu tetap; ada kalanya senang dan ada kalanya susah, seperti air laut yang mengalami pasang dan surut."},{"peribahasa":"asam di darat, ikan di laut (garam di laut asam di gunung) bertemu dalam belanga","makna":"Laki-laki dan perempuan, meskipun berasal dari tempat atau latar belakang yang berbeda, jika sudah berjodoh pada akhirnya akan bertemu dan bersatu."},{"peribahasa":"bagai menunggangkan air ke laut","makna":"Melakukan pekerjaan yang sia-sia atau tidak mendatangkan manfaat, seperti menolong orang yang tidak membutuhkan pertolongan."},{"peribahasa":"dalam laut boleh diajuk, dalam hati siapa tahu","makna":"Sesuatu yang tersembunyi di dalam hati atau pikiran seseorang tidak dapat diketahui atau diduga oleh orang lain."},{"peribahasa":"diam di laut masin tidak, diam di bandar tak meniru","makna":"Seseorang yang tidak terpengaruh atau tidak mau mengikuti kebiasaan baik di lingkungannya, meskipun berada di tempat yang seharusnya membentuk atau mempengaruhinya."},{"peribahasa":"garam di laut, asam di gunung bertemu dalam belanga juga","makna":"Laki-laki dan perempuan, meskipun berasal dari tempat yang jauh atau memiliki latar belakang yang berbeda, jika sudah berjodoh pada akhirnya akan bertemu dan bersatu."},{"peribahasa":"ikan di laut, asam di gunung, bertemu dalam belanga","makna":"Laki-laki dan perempuan, meskipun berasal dari tempat yang jauh atau memiliki latar belakang yang berbeda, jika sudah berjodoh pada akhirnya akan bertemu dan bersatu."},{"peribahasa":"ikan lagi di laut, lada garam sudah dalam sengkalan","makna":"Bersiap-siap untuk menikmati atau mengecap hasil dari suatu pekerjaan atau hal yang belum pasti berhasil atau belum tentu didapatkan."},{"peribahasa":"itik berenang di laut (air), mati kehausan","makna":"Seseorang yang memiliki banyak sumber daya atau kesempatan, namun tidak dapat memanfaatkannya untuk memenuhi kebutuhannya sendiri, sehingga tetap menderita kekurangan."},{"peribahasa":"jika benih yang baik jatuh ke laut, menjadi pulau","makna":"Seseorang yang memiliki sifat atau kualitas yang baik, di mana pun ia berada atau dalam kondisi apa pun, akan tetap menunjukkan kebaikan dan memberikan manfaat."},{"peribahasa":"kalau kail panjang sejengkal, jangan laut hendak diduga","makna":"Jika kemampuan atau pengetahuan yang dimiliki masih terbatas, janganlah mencoba melakukan hal-hal besar atau menantang yang melebihi kapasitas diri."},{"peribahasa":"karam di darat ada juga tinggal tungku lekar, karam di laut habis sekali","makna":"Jika mengalami kesulitan di tempat asal, masih ada harapan untuk mendapatkan bantuan; namun jika kesulitan terjadi di perantauan, kemungkinan besar akan kehilangan segalanya."},{"peribahasa":"karam di laut dapat direnangi, karam di hati bilakan sudah","makna":"Kesedihan mendalam akibat kehilangan orang yang dicintai lebih sulit diatasi daripada kerugian materi atau musibah fisik."},{"peribahasa":"laksana mengaprit di tengah laut, dipukul ombak jatuh ke tepi","makna":"Menggambarkan kondisi hidup yang tidak menentu, seringkali dalam kemiskinan, terutama saat berada di perantauan atau negeri asing."},{"peribahasa":"laut budi tepian akal","makna":"Seseorang yang memiliki pengetahuan, kecerdasan, dan kebijaksanaan yang sangat luas."},{"peribahasa":"laut ditembak, darat kena","makna":"Mendapatkan sesuatu yang tidak diniatkan atau lain dari yang diharapkan; atau suatu tindakan yang berdampak pada pihak yang tidak dituju secara langsung."},{"peribahasa":"laut ditimba akan kering","makna":"Betapapun banyaknya harta atau sumber daya yang dimiliki, jika terus-menerus digunakan tanpa henti, pada akhirnya akan habis juga."},{"peribahasa":"laut madu berpantaikan sakar (gula)","makna":"Perkataan yang manis dan menyenangkan yang keluar dari mulut orang yang berparas menarik."},{"peribahasa":"laut mana yang tak berombak, bumi mana yang tak ditimpa hujan","makna":"Setiap usaha atau kehidupan pasti akan menghadapi kesulitan, rintangan, atau cobaan; tidak ada yang selalu berjalan mulus."},{"peribahasa":"laut tidak membuang sungai, rimba tidak membuang latah","makna":"Orang yang berkuasa atau dermawan tidak akan menolak permintaan atau pertolongan yang diajukan kepadanya."},{"peribahasa":"membuang garam ke laut","makna":"Melakukan pekerjaan yang sia-sia atau tidak mendatangkan manfaat, seperti memberikan bantuan kepada pihak yang tidak membutuhkan."},{"peribahasa":"menambak gunung, menggarami air laut","makna":"Melakukan perbuatan yang sia-sia atau tidak mendatangkan manfaat, seperti memberikan bantuan kepada pihak yang tidak membutuhkan."},{"peribahasa":"menambak gunung, menggarami laut","makna":"Melakukan perbuatan yang sia-sia atau tidak mendatangkan manfaat, seperti memberikan bantuan kepada pihak yang tidak membutuhkan."},{"peribahasa":"menambak ke laut","makna":"Melakukan pekerjaan yang sia-sia atau tidak mendatangkan manfaat."},{"peribahasa":"menunggu laut kering","makna":"Melakukan pekerjaan yang sia-sia atau menunggu sesuatu yang mustahil terjadi."},{"peribahasa":"sekepal menjadi gunung, setitik menjadi laut","makna":"Sesuatu yang awalnya kecil atau sedikit dapat berkembang menjadi sangat besar atau banyak; atau membesar-besarkan masalah kecil."},{"peribahasa":"sungguhpun kawat yang dibentuk, ikan di laut yang diadang","makna":"Meskipun sesuatu terlihat tidak memiliki maksud tertentu, sebenarnya ada tujuan atau maksud tersembunyi di baliknya, seringkali untuk keuntungan pribadi."},{"peribahasa":"tak ada laut yang tak berombak","makna":"Setiap usaha atau kehidupan pasti akan menghadapi kesulitan, rintangan, atau bahaya; tidak ada yang selalu berjalan mulus."}]');
