insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('47664', 'le.bih', 'lebih', '', '', '["Adjektiva","Verba","Adverbia"]', '[{"nomor":"1","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"}],"definisi":"lewat dari semestinya (tentang ukuran, banyaknya, besarnya, dan sebagainya)","contoh":[{"nomor":2,"teks":"sudah kuberi Rp10.000,00 -- dari uang sekolahnya"},{"nomor":4,"teks":"ia merasa -- dari kawan-kawannya"},{"nomor":6,"teks":"panjangnya -- dari 3 cm"}]},{"nomor":"2","kelasKata":[{"kode":"v","nama":"Verba","tipe":"kelas_kata"}],"definisi":"(ber)sisa; ada sisanya","contoh":[{"nomor":2,"teks":"kalau kau bayar Rp5.000,00, --nya tinggal Rp2.000,00"}]},{"nomor":"3","kelasKata":[{"kode":"adv","nama":"Adverbia","tipe":"kelas_kata"}],"definisi":"bertambah; makin","contoh":[{"nomor":2,"teks":"kesehatannya sudah -- baik"},{"nomor":4,"teks":"harganya menjadi -- mahal"}]}]', '{"text":"[Jawa Kuno lěwih ''lebih, ulung, unggul, lebih tinggi, lebih baik; melebihi yang lain, amat, sangat, sekali, terkemuka, menonjol, terkenal; teristimewa, terutama; keunggulan, keulungan'']","languages":["Jawa Kuno"]}', '["berkelebihan","berlebih","berlebih-lebih","berlebih-lebihan","berlebihan","kelebihan","lebih-lebih","lebihan","melebih","melebih-lebihi","melebih-lebihkan","melebihi","melebihkan","selebihnya","terlebih","terlebih-lebih"]', '["lebih dahulu","lebih jauh","lebih kurang","lebih lagi"]', '["bagai ayam lebih penggunting","biar berputih tulang, jangan berputih mata (lebih baik berputih tulang daripada berputih mata)","dengan sesendok madu dapat lebih banyak ditangkap serangga daripada dengan cuka sesendok","daripada cempedak lebih baik nangka, daripada tidak, lebih baik ada","daripada hidup bercermin bangkai, lebih baik mati berkalang tanah","daripada hidup bercermin bangkai, lebih baik mati berkalang tanah (daripada hidup berlumur tahi, lebih baik mati bertimbun bunga)","hendak megah, berlawan lebih","imam yang adil lebih baik daripada hujan yang lebat","kalau sorok lebih dahulu daripada tokok, tidak mati babi","kalau tak punya bedil di pinggang, lebih baik berpedang lapang","kurang-kurang bubur, lebih-lebih sudu (sudu yang lebih)","kurang-kurang dikerah orang, lebih-lebih dia hendak datang","lebih baik mati berdiri daripada hidup berlutut","lebih baik mati berkalang tanah daripada hidup bercermin bangkai","lebih baik menyesal di hulu riam, daripada menyesal di hilir riam","lebih berharga mutiara sebutir daripada pasir sepantai","mengata dulang paku serpih, mengata orang awak yang lebih","padi segenggam dengan senang hati lebih baik daripada padi selumbung dengan bersusah hati"]', '["rumput tetangga lebih hijau"]', '[{"peribahasa":"bagai ayam lebih penggunting","makna":"Seseorang yang tidak lagi diperhitungkan dalam suatu perkumpulan karena telah jatuh miskin."},{"peribahasa":"biar berputih tulang, jangan berputih mata (lebih baik berputih tulang daripada berputih mata)","makna":"Lebih baik mati daripada menanggung malu yang teramat sangat."},{"peribahasa":"dengan sesendok madu dapat lebih banyak ditangkap serangga daripada dengan cuka sesendok","makna":"Dengan perkataan yang manis dan ramah-tamah, seseorang akan lebih mudah mendapatkan teman atau dukungan dibandingkan dengan perkataan yang tajam dan sikap yang masam."},{"peribahasa":"daripada cempedak lebih baik nangka, daripada tidak, lebih baik ada","makna":"Sesuatu yang sedikit atau kurang sempurna masih lebih baik daripada tidak ada sama sekali."},{"peribahasa":"daripada hidup bercermin bangkai, lebih baik mati berkalang tanah","makna":"Lebih baik mati daripada hidup menanggung malu yang teramat sangat."},{"peribahasa":"daripada hidup bercermin bangkai, lebih baik mati berkalang tanah (daripada hidup berlumur tahi, lebih baik mati bertimbun bunga)","makna":"Lebih baik mati daripada hidup menanggung malu yang teramat sangat."},{"peribahasa":"hendak megah, berlawan lebih","makna":"Seseorang yang terlalu ingin menunjukkan kemewahan atau kehebatan diri, pada akhirnya akan menghadapi kesulitan atau kesusahan; atau semakin banyak tantangan yang dihadapi, semakin besar pula ketenaran yang akan didapatkan."},{"peribahasa":"imam yang adil lebih baik daripada hujan yang lebat","makna":"Keberadaan seorang pemimpin yang adil dan bijaksana membawa manfaat yang jauh lebih besar dan membersihkan masyarakat dari kejahatan dan kecurangan, dibandingkan dengan manfaat hujan lebat yang hanya membersihkan kotoran fisik."},{"peribahasa":"kalau sorok lebih dahulu daripada tokok, tidak mati babi","makna":"Membual atau membanggakan diri sebelum melakukan usaha nyata, yang pada akhirnya tidak akan menghasilkan apa-apa."},{"peribahasa":"kalau tak punya bedil di pinggang, lebih baik berpedang lapang","makna":"Jika tidak memiliki kekuatan atau sumber daya yang cepat dan langsung, lebih baik memiliki kekuatan atau sumber daya yang lebih besar dan substansial untuk jangka panjang."},{"peribahasa":"kurang-kurang bubur, lebih-lebih sudu (sudu yang lebih)","makna":"Masalah kecil dapat menjadi besar jika terlalu banyak dibicarakan atau dicampuri oleh banyak orang; atau seseorang yang memiliki pengetahuan terbatas namun banyak bicara."},{"peribahasa":"kurang-kurang dikerah orang, lebih-lebih dia hendak datang","makna":"Seseorang yang terlalu bersemangat atau ingin terlibat, bahkan ketika tidak terlalu dibutuhkan atau diminta."},{"peribahasa":"lebih baik mati berdiri daripada hidup berlutut","makna":"Lebih baik mati dalam keadaan terhormat dan mempertahankan prinsip atau harga diri, daripada hidup dalam kehinaan, menyerah, atau tunduk pada penindasan."},{"peribahasa":"lebih baik mati berkalang tanah daripada hidup bercermin bangkai","makna":"Lebih baik mati daripada hidup menanggung malu yang teramat sangat."},{"peribahasa":"lebih baik menyesal di hulu riam, daripada menyesal di hilir riam","makna":"Lebih baik menyesali atau membatalkan suatu pekerjaan atau keputusan di awal sebelum terlambat, daripada menyesal di kemudian hari setelah pekerjaan atau keputusan itu tidak dapat diubah lagi."},{"peribahasa":"lebih berharga mutiara sebutir daripada pasir sepantai","makna":"Sesuatu yang sedikit namun memiliki kualitas atau nilai yang tinggi jauh lebih berharga daripada sesuatu yang banyak namun tidak memiliki nilai atau kualitas."},{"peribahasa":"mengata dulang paku serpih, mengata orang awak yang lebih","makna":"Mencela atau mengkritik orang lain, padahal diri sendiri memiliki kekurangan atau kesalahan yang lebih besar."},{"peribahasa":"padi segenggam dengan senang hati lebih baik daripada padi selumbung dengan bersusah hati","manaka":"Ketenangan batin dan kebahagiaan lebih berharga daripada kekayaan materi; lebih baik hidup sederhana namun bahagia daripada kaya raya namun gelisah."}]');
