las_kata"}],"definisi":"berdiri sendiri; bebas","contoh":[{"nomor":2,"teks":"negara itu sudah -- dari cengkeraman penjajah"}]},{"nomor":"10","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"}],"definisi":"tidak melekat lagi; hilang","contoh":[{"nomor":2,"teks":"kejadian itu tidak pernah -- dari ingatannya"}]},{"nomor":"11","kelasKata":[{"kode":"a","nama":"Adjektiva","tipe":"kelas_kata"}],"definisi":"sesudah; sehabis","contoh":[{"nomor":2,"teks":"-- salat subuh, kami selalu berjalan-jalan"}]}]', null, '["berlepas","kelepasan","keterlepasan","lepasan","melepas","melepasi","melepaskan","memperlepas","pelepas","pelepasan","selepas","selepas-lepas","terlepas"]', '["lepas angin","lepas ayam","lepas bebas","lepas buku","lepas burung","lepas cakap","lepas kendali","lepas kira-kira","lepas kontrol","lepas landas","lepas malu","lepas pantai","lepas tagih","lepas tangan","lepas tunda","lepas unggas","lepas vokal"]', '["ayam lepas, tangan bau tahi (bercirit)","bagai ayam lepas taji","bagai kucing lepas senja","bak mandi di air kiambang, pelak lepas gatal pun datang","ganti (menggantikan) tikar (lepas bantal berganti tikar)","lepas bantal, berganti tikar","lepas dari mulut harimau, jatuh ke mulut buaya","melepas anjing terjepit, setelah lepas ia menggigit","melepaskan anjing tersepit, sesudah lepas dia menggigit","mulut manis jangan percaya, lepas dari tangan jangan diharap","nyamuk mati, gatal tak lepas","seperti anak panah lepas dari busur","seperti bujuk lepas dari bubu","seperti kuda lepas dari pingitan"]', '["seperti kijang lepas ke rimba"]', '[{"peribahasa":"ayam lepas, tangan bau tahi (bercirit)","makna":"Melakukan perbuatan yang tercela, meskipun pada akhirnya terbebas dari tuduhan, nama baik tetap tercemar."},{"peribahasa":"bagai ayam lepas taji","makna":"Seseorang yang kehilangan kekuasaan atau pengaruhnya."},{"peribahasa":"bagai kucing lepas senja","makna":"Seseorang yang sangat sulit ditemukan atau dicari."},{"peribahasa":"bak mandi di air kiambang, pelak lepas gatal pun datang","makna":"Kesenangan atau kegembiraan yang hanya sesaat, setelah itu datanglah kesusahan atau penderitaan."},{"peribahasa":"ganti (menggantikan) tikar (lepas bantal berganti tikar)","makna":"Menikahi saudara atau kerabat dari istri yang telah meninggal."},{"peribahasa":"lepas bantal, berganti tikar","makna":"Menikahi saudara atau kerabat dari istri yang telah meninggal."},{"peribahasa":"lepas dari mulut harimau, jatuh ke mulut buaya","makna":"Terhindar dari satu bahaya, tetapi masuk ke dalam bahaya lain yang lebih besar."},{"peribahasa":"melepas anjing terjepit, setelah lepas ia menggigit","makna":"Menolong orang yang tidak tahu berterima kasih, bahkan berbalik memusuhi."},{"peribahasa":"melepaskan anjing tersepit, sesudah lepas dia menggigit","makna":"Menolong orang yang tidak tahu berterima kasih, bahkan berbalik memusuhi."},{"peribahasa":"mulut manis jangan percaya, lepas dari tangan jangan diharap","makna":"Jangan mudah percaya pada janji-janji manis, dan jangan berharap kembali sesuatu yang sudah tidak ada dalam genggaman kita."},{"peribahasa":"nyamuk mati, gatal tak lepas","makna":"Meskipun orang yang menyusahkan sudah tidak ada, akibat dari perbuatannya masih terasa."},{"peribahasa":"seperti anak panah lepas dari busur","makna":"Sesuatu yang melaju dengan sangat cepat."},{"peribahasa":"seperti bujuk lepas dari bubu","makna":"Orang yang berhasil meloloskan diri dari suatu kesulitan atau bahaya dengan susah payah."},{"peribahasa":"seperti kuda lepas dari pingitan","makna":"Seseorang yang merasa sangat bebas dan gembira setelah terlepas dari kungkungan atau batasan."}]');
