insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('48937', 'le.sung', 'lesung', '', '', '["Nomina"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"lumpang kayu panjang (untuk menumbuk padi dan sebagainya)","contoh":[]}]', '{"text":"[Jawa Kuno lěsuṅ ''lesung'']","languages":["Jawa Kuno"]}', '[]', '["lesung gening","lesung indik","lesung kincir","lesung pinang","lesung pipi"]', '["adat periuk berkerak, adat lesung berdedak","antan patah, lesung hilang","asa ayam hendak ke lesung, asa itik hendak ke pelimbahan","bagai bertemu alu dengan lesung, beras kita yang terserak, ayam orang yang kenyang","bertelingkah bagai antan di lesung, ayam juga yang kenyang","bertelingkuh antan di lesung, ayam juga yang kenyang","bertelingkuh bagai antan di lesung","ke mana dialih, lesung berdedak juga","lesung mencari alu","menghendaki urat lesung","menumbuk di lesung, bertanak di periuk","menumbuk di periuk, bertanak di lesung","sebuah lesung ada seekor ayam jantannya (atau pemimpinnya)","seperti birah tumbuh di tepi lesung","terselingkuh antan di lesung ayam juga yang kenyang","yang berkurap pembawa buluh, yang buta pengembus lesung"]', '[]', '[{"peribahasa":"adat periuk berkerak, adat lesung berdedak","makna":"Setiap pekerjaan atau usaha pasti ada bekas atau sisanya; di mana ada kerja, di situ ada hasil."},{"peribahasa":"antan patah, lesung hilang","makna":"Tertimpa musibah atau kemalangan secara berturut-turut."},{"peribahasa":"asa ayam hendak ke lesung, asa itik hendak ke pelimbahan","makna":"Setiap orang memiliki keinginan atau harapan yang sesuai dengan kodrat atau keadaannya."},{"peribahasa":"bagai bertemu alu dengan lesung, beras kita yang terserak, ayam orang yang kenyang","makna":"Jika dua orang yang berseteru bertemu, sering kali orang lain yang mengambil keuntungan dari perselisihan mereka."},{"peribahasa":"bertelingkah bagai antan di lesung, ayam juga yang kenyang","makna":"Dua orang yang berselisih atau bertengkar, tetapi orang lain yang mendapat keuntungan dari perselisihan itu."},{"peribahasa":"bertelingkuh antan di lesung, ayam juga yang kenyang","makna":"Dua orang yang berselisih atau bertengkar, tetapi orang lain yang mendapat keuntungan dari perselisihan itu."},{"peribahasa":"bertelingkuh bagai antan di lesung","makna":"Selalu berselisih atau tidak pernah sependapat."},{"peribahasa":"ke mana dialih, lesung berdedak juga","makna":"Meskipun suatu hal dipindahkan atau diubah, sifat aslinya tidak akan berubah."},{"peribahasa":"lesung mencari alu","makna":"Perempuan yang mencari laki-laki; sesuatu yang tidak lazim."},{"peribahasa":"menghendaki urat lesung","makna":"Menginginkan sesuatu yang tidak mungkin atau mustahil."},{"peribahasa":"menumbuk di lesung, bertanak di periuk","makna":"Melakukan sesuatu sesuai dengan aturan atau kebiasaan yang berlaku."},{"peribahasa":"menumbuk di periuk, bertanak di lesung","makna":"Melakukan sesuatu yang menyalahi aturan atau kebiasaan."},{"peribahasa":"sebuah lesung ada seekor ayam jantannya (atau pemimpinnya)","makna":"Dalam setiap kelompok atau komunitas, pasti ada seorang pemimpinnya."},{"peribahasa":"seperti birah tumbuh di tepi lesung","makna":"Anak yang tumbuh subur dan sehat."},{"peribahasa":"terselingkuh antan di lesung ayam juga yang kenyang","makna":"Dua orang yang berselisih atau bertengkar, tetapi orang lain yang mendapat keuntungan dari perselisihan itu."},{"peribahasa":"yang berkurap pembawa buluh, yang buta pengembus lesung","makna":"Setiap orang memiliki tugas atau pekerjaan yang sesuai dengan kemampuannya."}]');
