erlicin"]', '["licin belut","licin lecat","licin licau","licin lindap","licin melecat","licin tandas"]', '["berminyak biar licin (lecak)","datar bak lantai papan, licin bak dinding cermin","lebuh sempit kuda penyepak, jalan licin tebing berkelok","licin bagai belut","licin karena minyak berminta, elok karena kain berselang","mati-mati berminyak biar licin","muka licin, ekor berkedal"]', '[]', '[{"peribahasa":"berminyak biar licin (lecak)","makna":"Jika sudah terlanjur berbuat jahat, biarlah sekalian saja, jangan tanggung-tanggung."},{"peribahasa":"datar bak lantai papan, licin bak dinding cermin","makna":"Menggambarkan sesuatu yang sangat rata dan bersih."},{"peribahasa":"lebuh sempit kuda penyepak, jalan licin tebing berkelok","makna":"Dalam keadaan sulit atau terdesak, seseorang akan melakukan apa saja untuk menyelamatkan diri."},{"peribahasa":"licin bagai belut","makna":"Seseorang yang sangat licik dan sulit ditangkap atau dikenai hukuman."},{"peribahasa":"licin karena minyak berminta, elok karena kain berselang","makna":"Kecantikan atau kebaikan yang didapat dari hasil meminta-minta atau menipu."},{"peribahasa":"mati-mati berminyak biar licin","makna":"Jika sudah terlanjur berbuat jahat, biarlah sekalian saja, jangan tanggung-tanggung."},{"peribahasa":"muka licin, ekor berkedal","makna":"Seseorang yang tampak baik di depan, tetapi berbuat jahat di belakang."}]');
