insert into kbbi (_id, nama, kata, jenis, akar_kata, kelas_kata, makna, etimologi, kata_turunan, gabungan_kata, peribahasa, idiom, peribahasa_dan_makna) values ('50297', 'lu.ar', 'luar', '', '', '["Nomina","Nomina","Nomina"]', '[{"nomor":"1","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"daerah, tempat, dan sebagainya yang tidak merupakan bagian dari sesuatu itu sendiri","contoh":[{"nomor":2,"teks":"ia berdiri di -- gedung"},{"nomor":4,"teks":"lima tahun ia tinggal di -- negeri"}]},{"nomor":"2","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"bukan dari lingkungan (keluarga, negeri, daerah, dan sebagainya) sendiri; asing","contoh":[{"nomor":2,"teks":"meskipun ia orang --, tetapi sudah seperti keluarga sendiri"}]},{"nomor":"3","kelasKata":[{"kode":"n","nama":"Nomina","tipe":"kelas_kata"}],"definisi":"bagian (sisi, permukaan, dan sebagainya) yang tidak di dalam: obat untuk mengobati bagian luar tubuh (kulit dan sebagainya)","contoh":[{"nomor":2,"teks":"merek kecap itu tertempel di -- botol"},{"nomor":4,"teks":"obat --"}]}]', null, '["luaran","meluar","meluarkan","terluar"]', '["luar angkasa","luar batas","luar bicara","luar dalam","luar dugaan","luar jaringan","luar kendali","luar kepala","luar negeri","luar nikah","luar panggung","luar ruang","luar siar"]', '["berketuk di luar sangkar, bertanam di luar pagar","bernapas ke luar badan","di luar bagai madu, di dalam bagai empedu","di luar harimau, di dalam kambing","di luar merah, di dalam pahit","elok kata dalam mufakat, buruk kata di luar mufakat","masak di luar, mentah di dalam","memukul canang ke luar kota","mencampakkan batu ke luar","pepat di luar, pancung di dalam","pepat di luar, rancung (pancunya) di dalam","rumah terbakar, tikus habis ke luar","seperti buah kedempung, di luar berisi di dalam kosong","tidak ada orang menggaruk ke luar badan"]', '["berteras ke luar (bagai pimping)","di luar nalar"]', '[{"peribahasa":"berketuk di luar sangkar, bertanam di luar pagar","makna":"Melakukan sesuatu yang tidak pada tempatnya atau tidak sesuai dengan kebiasaan."},{"peribahasa":"bernapas ke luar badan","makna":"Sangat kelelahan atau hampir mati."},{"peribahasa":"di luar bagai madu, di dalam bagai empedu","makna":"Seseorang yang tampak baik di luar, tetapi sebenarnya jahat atau busuk hatinya."},{"peribahasa":"di luar harimau, di dalam kambing","makna":"Seseorang yang tampak berani atau garang di luar, tetapi sebenarnya penakut atau lemah."},{"peribahasa":"di luar merah, di dalam pahit","makna":"Sesuatu yang tampak indah atau menarik di luar, tetapi sebenarnya tidak baik atau mengecewakan."},{"peribahasa":"elok kata dalam mufakat, buruk kata di luar mufakat","makna":"Keputusan yang baik adalah hasil musyawarah, sedangkan keputusan yang buruk adalah hasil dari tindakan sendiri tanpa persetujuan bersama."},{"peribahasa":"masak di luar, mentah di dalam","makna":"Seseorang yang tampak pandai atau berpengalaman di luar, tetapi sebenarnya tidak memiliki pengetahuan yang mendalam."},{"peribahasa":"memukul canang ke luar kota","makna":"Menyebarkan berita atau informasi ke mana-mana."},{"peribahasa":"mencampakkan batu ke luar","makna":"Membuang sesuatu yang tidak berguna atau tidak diinginkan."},{"peribahasa":"pepat di luar, pancung di dalam","makna":"Seseorang yang tampak jujur atau baik di luar, tetapi sebenarnya licik atau jahat."},{"peribahasa":"pepat di luar, rancung (pancunya) di dalam","makna":"Seseorang yang tampak jujur atau baik di luar, tetapi sebenarnya licik atau jahat."},{"peribahasa":"rumah terbakar, tikus habis ke luar","makna":"Dalam keadaan kacau atau bahaya, orang-orang yang tidak bertanggung jawab akan melarikan diri."},{"peribahasa":"seperti buah kedempung, di luar berisi di dalam kosong","makna":"Seseorang yang tampak kaya atau berilmu di luar, tetapi sebenarnya tidak memiliki apa-apa."},{"peribahasa":"tidak ada orang menggaruk ke luar badan","makna":"Tidak ada orang yang mau merugikan diri sendiri."}]');
